import{_ as l,c as i,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"Ollama","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/Ollama-AI工具.md","filePath":"github汇总/AI工具/Ollama-AI工具.md"}'),o={name:"github汇总/AI工具/Ollama-AI工具.md"};function h(t,a,n,m,d,c){return e(),i("div",null,a[0]||(a[0]=[r('<h1 id="ollama" tabindex="-1">Ollama <a class="header-anchor" href="#ollama" aria-label="Permalink to “Ollama”">​</a></h1><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>Ollama</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>AI工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>在本地运行大语言模型需要自己下载模型、配置环境、处理各种依赖，特别麻烦</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><ul><li>在本地电脑上轻松运行大语言模型</li><li>超简单的命令行工具</li><li>一条命令就能下载和运行模型</li><li>REST API，可在应用中集成</li><li>支持超多模型（Llama 3、Phi 3、Mistral、Gemma等）</li><li>跨平台支持（macOS、Windows、Linux）</li><li>支持自定义模型，可导入GGUF模型</li><li>支持Web UI</li></ul><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>超简单的命令行工具，一条命令就能下载和运行模型</li><li>支持超多模型（Llama 3、Phi 3、Mistral、Gemma等）</li><li>跨平台支持（macOS、Windows、Linux）</li><li>安装超简单，下载安装包或用Docker</li><li>支持自定义模型，可导入GGUF模型</li><li>提供REST API，可在应用中集成</li><li>支持Web UI，方便在浏览器中使用</li><li>保护隐私，数据不离开本地</li><li>最受欢迎的本地LLM运行工具之一</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/ollama/ollama" target="_blank" rel="noreferrer">https://github.com/ollama/ollama</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>适用于想在本地体验大语言模型的开发者和爱好者，支持macOS、Windows、Linux</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li>系统要求：支持macOS、Windows、Linux</li><li>网络连接：可访问互联网下载模型</li></ol><h3 id="主路径-安装ollama" tabindex="-1">主路径：安装Ollama <a class="header-anchor" href="#主路径-安装ollama" aria-label="Permalink to “主路径：安装Ollama”">​</a></h3><h4 id="步骤1-安装ollama" tabindex="-1">步骤1：安装Ollama <a class="header-anchor" href="#步骤1-安装ollama" aria-label="Permalink to “步骤1：安装Ollama”">​</a></h4><ul><li>步骤目标：安装Ollama</li><li>执行位置：根据系统选择方式</li><li>macOS/Windows：访问<a href="https://ollama.xn--com-128do1uy9nba2573gca903o" target="_blank" rel="noreferrer">https://ollama.com下载安装包安装</a></li><li>Linux：使用安装脚本 <code>curl -fsSL https://ollama.com/install.sh | sh</code></li><li>Docker：<code>docker run -d -v ollama:/root/.ollama -p 11434:11434 --name ollama ollama/ollama</code></li><li>成功标志：安装完成，可运行<code>ollama --version</code></li><li>失败处理：查看官方安装文档</li></ul><h4 id="步骤2-运行模型" tabindex="-1">步骤2：运行模型 <a class="header-anchor" href="#步骤2-运行模型" aria-label="Permalink to “步骤2：运行模型”">​</a></h4><ul><li>步骤目标：下载并运行模型</li><li>执行位置：终端/命令行</li><li>完整命令：<code>ollama run llama3</code></li><li>成功标志：模型下载完成，进入交互模式</li><li>失败处理：检查网络连接，确认模型名称正确</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ol><li>检查命令：<code>ollama --version</code></li><li>运行模型：<code>ollama run llama3</code></li><li>官方网站：<a href="https://ollama.com" target="_blank" rel="noreferrer">https://ollama.com</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ol><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li>现象：安装失败 <ul><li>可能原因：系统不兼容或权限问题</li><li>解决步骤：确认系统符合要求，使用管理员权限（Windows）或sudo（Linux）</li></ul></li><li>现象：模型下载失败 <ul><li>可能原因：网络问题或模型名称错误</li><li>解决步骤：检查网络连接，确认模型名称正确</li></ul></li><li>现象：模型运行慢 <ul><li>可能原因：硬件配置不足</li><li>解决步骤：考虑使用更小的模型，或升级硬件</li></ul></li></ol><h3 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h3><p>如需深入了解详细使用方法和模型列表，可访问官方网站：<a href="https://ollama.com" target="_blank" rel="noreferrer">https://ollama.com</a> <a href="/网络环境.html">海外网络环境配置 →</a></p>',31)]))}const f=l(o,[["render",h]]);export{b as __pageData,f as default};
